changeSet.sql:
CREATE TABLE class_level_reward_group ( reward_group_id uuid PRIMARY KEY DEFAULT gen_random_uuid(), class_id uuid NOT NULL REFERENCES character_class(class_id) ON DELETE CASCADE, class_feature_id uuid REFERENCES class_feature(class_feature_id) ON DELETE SET NULL, class_level INT NOT NULL CHECK (class_level BETWEEN 1 AND 20), group_kind TEXT NOT NULL CHECK (group_kind IN ('AUTO','CHOICE')), prompt_ru TEXT, prompt_en TEXT, description TEXT, choose_min INT NOT NULL DEFAULT 0, choose_max INT NOT NULL DEFAULT 1, repeatable BOOLEAN NOT NULL DEFAULT FALSE, sort_order INT NOT NULL DEFAULT 0, CONSTRAINT chk_class_reward_group_choice_count CHECK (choose_min >= 0 AND choose_max >= choose_min) );
CREATE TABLE class_level_reward_option ( reward_option_id uuid PRIMARY KEY DEFAULT gen_random_uuid(), reward_group_id uuid NOT NULL REFERENCES class_level_reward_group(reward_group_id) ON DELETE CASCADE, option_key TEXT, label_ru TEXT NOT NULL, label_en TEXT, description TEXT, is_recommended BOOLEAN NOT NULL DEFAULT FALSE, sort_order INT NOT NULL DEFAULT 0, UNIQUE (reward_option_id, reward_group_id) );
CREATE UNIQUE INDEX uq_class_reward_option_key ON class_level_reward_option(reward_group_id, option_key) WHERE option_key IS NOT NULL;
CREATE TABLE class_level_reward_grant ( reward_grant_id uuid PRIMARY KEY DEFAULT gen_random_uuid(), reward_group_id uuid REFERENCES class_level_reward_group(reward_group_id) ON DELETE CASCADE, reward_option_id uuid REFERENCES class_level_reward_option(reward_option_id) ON DELETE CASCADE, grant_type TEXT NOT NULL, label_ru TEXT, label_en TEXT, description TEXT, sort_order INT NOT NULL DEFAULT 0, CONSTRAINT chk_class_reward_grant_owner CHECK ( (reward_group_id IS NOT NULL AND reward_option_id IS NULL) OR (reward_group_id IS NULL AND reward_option_id IS NOT NULL) ) );
CREATE TABLE class_level_reward_grant_feature ( reward_grant_id uuid PRIMARY KEY REFERENCES class_level_reward_grant(reward_grant_id) ON DELETE CASCADE, class_feature_id uuid NOT NULL REFERENCES class_feature(class_feature_id) );
CREATE TABLE class_level_reward_grant_subclass ( reward_grant_id uuid PRIMARY KEY REFERENCES class_level_reward_grant(reward_grant_id) ON DELETE CASCADE, subclass_id uuid NOT NULL REFERENCES subclass(subclass_id) );
CREATE TABLE class_level_reward_grant_feat ( reward_grant_id uuid PRIMARY KEY REFERENCES class_level_reward_grant(reward_grant_id) ON DELETE CASCADE, feat_id uuid NOT NULL REFERENCES feat(feat_id) );
CREATE TABLE class_level_reward_grant_spell ( reward_grant_id uuid PRIMARY KEY REFERENCES class_level_reward_grant(reward_grant_id) ON DELETE CASCADE, spell_id uuid REFERENCES spell(spell_id), spell_level INT, school_id uuid REFERENCES spell_school(spell_school_id), choose_count INT NOT NULL DEFAULT 1, raw_filter_text TEXT, CONSTRAINT chk_class_reward_spell_choice_count CHECK (choose_count > 0) );
CREATE TABLE class_level_reward_grant_skill_proficiency ( reward_grant_id uuid PRIMARY KEY REFERENCES class_level_reward_grant(reward_grant_id) ON DELETE CASCADE, skill_id uuid REFERENCES skill(skill_id), choose_count INT NOT NULL DEFAULT 1, any_skill BOOLEAN NOT NULL DEFAULT FALSE, raw_filter_text TEXT, CONSTRAINT chk_class_reward_skill_choice_count CHECK (choose_count > 0) );
CREATE TABLE class_level_reward_grant_skill_option ( reward_grant_id uuid NOT NULL REFERENCES class_level_reward_grant_skill_proficiency(reward_grant_id) ON DELETE CASCADE, skill_id uuid NOT NULL REFERENCES skill(skill_id), PRIMARY KEY (reward_grant_id, skill_id) );
CREATE TABLE class_level_reward_grant_ability_score ( reward_grant_id uuid PRIMARY KEY REFERENCES class_level_reward_grant(reward_grant_id) ON DELETE CASCADE, ability_score_id uuid REFERENCES ability_score(ability_score_id), choose_count INT NOT NULL DEFAULT 1, bonus_per_choice INT NOT NULL DEFAULT 1, total_bonus INT, max_per_ability INT, max_score INT, raw_filter_text TEXT, CONSTRAINT chk_class_reward_ability_choice_count CHECK (choose_count > 0), CONSTRAINT chk_class_reward_ability_bonus CHECK (bonus_per_choice <> 0) );
CREATE TABLE class_level_reward_grant_ability_option ( reward_grant_id uuid NOT NULL REFERENCES class_level_reward_grant_ability_score(reward_grant_id) ON DELETE CASCADE, ability_score_id uuid NOT NULL REFERENCES ability_score(ability_score_id), PRIMARY KEY (reward_grant_id, ability_score_id) );
CREATE TABLE class_level_reward_grant_numeric_modifier ( reward_grant_id uuid PRIMARY KEY REFERENCES class_level_reward_grant(reward_grant_id) ON DELETE CASCADE, modifier_key TEXT NOT NULL, target_kind TEXT NOT NULL, target_label_ru TEXT, target_label_en TEXT, amount NUMERIC(12,3), dice_formula_id uuid REFERENCES dice_formula(dice_formula_id), unit_text TEXT, duration_text TEXT, stacking_rule TEXT, notes TEXT );
CREATE TABLE class_level_reward_grant_custom_text ( reward_grant_id uuid PRIMARY KEY REFERENCES class_level_reward_grant(reward_grant_id) ON DELETE CASCADE, title_ru TEXT, title_en TEXT, body TEXT NOT NULL, user_editable BOOLEAN NOT NULL DEFAULT TRUE );
CREATE TABLE character_reward_selection ( character_reward_selection_id uuid PRIMARY KEY DEFAULT gen_random_uuid(), character_id uuid NOT NULL REFERENCES characters(id) ON DELETE CASCADE, reward_group_id uuid NOT NULL REFERENCES class_level_reward_group(reward_group_id) ON DELETE CASCADE, reward_option_id uuid NOT NULL, selected_at TIMESTAMPTZ NOT NULL DEFAULT now(), note_text TEXT, CONSTRAINT fk_character_reward_selection_option_group FOREIGN KEY (reward_option_id, reward_group_id) REFERENCES class_level_reward_option(reward_option_id, reward_group_id) ON DELETE CASCADE );
CREATE UNIQUE INDEX uq_character_reward_selection_option ON character_reward_selection(character_id, reward_group_id, reward_option_id);
CREATE TABLE character_reward_ability_score_selection ( character_reward_selection_id uuid NOT NULL REFERENCES character_reward_selection(character_reward_selection_id) ON DELETE CASCADE, reward_grant_id uuid NOT NULL REFERENCES class_level_reward_grant_ability_score(reward_grant_id), ability_score_id uuid NOT NULL REFERENCES ability_score(ability_score_id), bonus_amount INT NOT NULL, PRIMARY KEY (character_reward_selection_id, reward_grant_id, ability_score_id) );
CREATE TABLE character_reward_skill_selection ( character_reward_selection_id uuid NOT NULL REFERENCES character_reward_selection(character_reward_selection_id) ON DELETE CASCADE, reward_grant_id uuid NOT NULL REFERENCES class_level_reward_grant_skill_proficiency(reward_grant_id), skill_id uuid NOT NULL REFERENCES skill(skill_id), PRIMARY KEY (character_reward_selection_id, reward_grant_id, skill_id) );
CREATE TABLE character_reward_spell_selection ( character_reward_selection_id uuid NOT NULL REFERENCES character_reward_selection(character_reward_selection_id) ON DELETE CASCADE, reward_grant_id uuid NOT NULL REFERENCES class_level_reward_grant_spell(reward_grant_id), spell_id uuid NOT NULL REFERENCES spell(spell_id), PRIMARY KEY (character_reward_selection_id, reward_grant_id, spell_id) );
CREATE INDEX idx_class_reward_group_class_level ON class_level_reward_group(class_id, class_level, sort_order); CREATE INDEX idx_class_reward_grant_group ON class_level_reward_grant(reward_group_id); CREATE INDEX idx_class_reward_grant_option ON class_level_reward_grant(reward_option_id); CREATE INDEX idx_character_reward_selection_character ON character_reward_selection(character_id);

rollback.sql:
DROP TABLE IF EXISTS character_reward_spell_selection;
DROP TABLE IF EXISTS character_reward_skill_selection;
DROP TABLE IF EXISTS character_reward_ability_score_selection;
DROP TABLE IF EXISTS character_reward_selection;
DROP TABLE IF EXISTS class_level_reward_grant_custom_text;
DROP TABLE IF EXISTS class_level_reward_grant_numeric_modifier;
DROP TABLE IF EXISTS class_level_reward_grant_ability_option;
DROP TABLE IF EXISTS class_level_reward_grant_ability_score;
DROP TABLE IF EXISTS class_level_reward_grant_skill_option;
DROP TABLE IF EXISTS class_level_reward_grant_skill_proficiency;
DROP TABLE IF EXISTS class_level_reward_grant_spell;
DROP TABLE IF EXISTS class_level_reward_grant_feat;
DROP TABLE IF EXISTS class_level_reward_grant_subclass;
DROP TABLE IF EXISTS class_level_reward_grant_feature;
DROP TABLE IF EXISTS class_level_reward_grant;
DROP TABLE IF EXISTS class_level_reward_option;
DROP TABLE IF EXISTS class_level_reward_group;
